  if coalesce(NEW.sequence_no::text, '') = '' or NEW.sequence_no = 0 then 
    select max(sequence_no) into STRICT NEW.sequence_no
    from sc_acc_journal_detail_firm 
    where doc_type = NEW.doc_type
    and doc_no = NEW.doc_no
    and journal_date = NEW.journal_date
    and branch_id = NEW.branch_id;
    NEW.sequence_no := coalesce(NEW.sequence_no,0) + 1;
  end if;

  if coalesce(NEW.dr_amount::text, '') = '' then NEW.dr_amount :=0;end if;
  if coalesce(NEW.cr_amount::text, '') = '' then NEW.cr_amount :=0;end if;
  if coalesce(NEW.post_system::text, '') = '' then NEW.post_system :=0;end if;

   if NEW.entry_id <> 'soat' and NEW.dr_amount = 0 and  NEW.cr_amount =0 then
      NEW.branch_id := 'XX';
      NEW.journal_date := statement_timestamp();
   end if;
   
RETURN NEW;
end
